import{_ as a,o as s,c as i,ae as t}from"./chunks/framework.CY_fclge.js";const u=JSON.parse('{"title":"Space Algebra","description":"","frontmatter":{},"headers":[],"relativePath":"Space-Algebra.md","filePath":"Space-Algebra.md"}'),l={name:"Space-Algebra.md"};function p(n,e,o,c,r,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="space-algebra" tabindex="-1">Space Algebra <a class="header-anchor" href="#space-algebra" aria-label="Permalink to &quot;Space Algebra&quot;">​</a></h1><p><code>.me</code> thinks in <strong>spaces</strong>.</p><p>Not schemas. Not tables. Not object classes.</p><p>A <strong>space</strong> is a region of meaning that can contain other spaces.</p><p>Everything else follows from set laws.</p><h2 id="core-rule" tabindex="-1">Core Rule <a class="header-anchor" href="#core-rule" aria-label="Permalink to &quot;Core Rule&quot;">​</a></h2><p>A space can contain spaces.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>space ⊇ subspace ⊇ subspace ⊇ subspace</span></span></code></pre></div><p>Examples:</p><ul><li><code>profile</code> is a space</li><li><code>profile.contact</code> is a subspace of <code>profile</code></li><li><code>wallet.hidden</code> is a subspace of <code>wallet</code></li><li><code>friends[age &gt; 18]</code> is a selected subspace of <code>friends</code></li></ul><p>In <code>.me</code>, paths are how we navigate nested spaces:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.profile.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Abella&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.profile.contact.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">email</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;abella@neurons.me&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.wallet[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vault-key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">me.wallet.hidden.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">note</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;private&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h2 id="namespace" tabindex="-1">Namespace <a class="header-anchor" href="#namespace" aria-label="Permalink to &quot;Namespace&quot;">​</a></h2><p>A <strong>namespace</strong> is a named space.</p><p>Examples:</p><ul><li><code>self</code></li><li><code>kernel</code></li><li><code>ana</code></li><li><code>family.photos</code></li></ul><p>In protocol form:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>me://self:read/profile</span></span>
<span class="line"><span>me://kernel:export/snapshot</span></span>
<span class="line"><span>me://family.photos:read/2026.vacation.cover</span></span></code></pre></div><p>So:</p><ul><li><code>namespace</code> names the space</li><li><code>selector</code> states the operation</li><li><code>path</code> identifies the subspace</li></ul><h2 id="set-view" tabindex="-1">Set View <a class="header-anchor" href="#set-view" aria-label="Permalink to &quot;Set View&quot;">​</a></h2><p>We can describe a space by the sets that act on it:</p><ul><li><code>A</code> = audience set</li><li><code>T</code> = topology set</li><li><code>C</code> = capability set</li><li><code>P</code> = path / subspace set</li></ul><p>These are not different ontologies. They are different views of the same space.</p><h2 id="space-predicates" tabindex="-1">Space Predicates <a class="header-anchor" href="#space-predicates" aria-label="Permalink to &quot;Space Predicates&quot;">​</a></h2><p>The common adjectives are just set statements:</p><ul><li><strong>public space</strong>: the readable audience is broadly open</li><li><strong>private space</strong>: the audience is tightly bounded, often <code>{self}</code></li><li><strong>shared space</strong>: the audience contains more than one principal</li><li><strong>encrypted space</strong>: readable membership is enforced cryptographically</li><li><strong>replicated space</strong>: the topology has multiple carriers</li></ul><p>Examples:</p><ul><li><code>wallet</code> may be a <strong>private encrypted space</strong></li><li><code>family.photos</code> may be a <strong>shared replicated encrypted space</strong></li><li><code>profile.public</code> may be a <strong>public space</strong></li></ul><p>No new noun is required beyond <code>space</code>.</p><h2 id="refinement" tabindex="-1">Refinement <a class="header-anchor" href="#refinement" aria-label="Permalink to &quot;Refinement&quot;">​</a></h2><p>More specific spaces are subsets of less specific spaces.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>profile.contact.email ⊆ profile.contact ⊆ profile</span></span>
<span class="line"><span>wallet.hidden ⊆ wallet</span></span></code></pre></div><p>This same law appears across the system:</p><ul><li>deeper path -&gt; smaller semantic region</li><li>tighter audience -&gt; smaller readable set</li><li>tighter context -&gt; smaller resolution set</li><li>tighter capability -&gt; smaller action set</li></ul><h2 id="encryption-as-membership" tabindex="-1">Encryption As Membership <a class="header-anchor" href="#encryption-as-membership" aria-label="Permalink to &quot;Encryption As Membership&quot;">​</a></h2><p>Encryption does not create a different universe. It creates a stricter readable membership over a space.</p><p>Examples:</p><ul><li>a private space may have <code>A = {self}</code></li><li>a shared encrypted space may have <code>A = {me ∪ wife}</code></li></ul><p>The topology can be large while the readable audience stays small:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T = {home-daemon, office-daemon, phone}</span></span>
<span class="line"><span>A = {me, wife}</span></span></code></pre></div><p>That means the same space may be replicated widely without becoming readable widely.</p><h2 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h2><p>This gives <code>.me</code> one ontology instead of many.</p><ul><li><code>.me</code> declares, creates, and navigates spaces</li><li><code>cleaker</code> records, routes, and transports spaces</li><li><code>monad.ai</code> serves, resolves, and persists spaces</li></ul><p>The system stays unified because everything still reduces to:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>space inside space inside space</span></span></code></pre></div><p>And all of it follows set law.</p>`,48)])])}const g=a(l,[["render",p]]);export{u as __pageData,g as default};
